export const adminDashboardDesign = {
  colors: {
    sidebar: "bg-gray-900 text-white",
    navbar: "bg-white shadow-md",
    hover: "hover:bg-gray-800",
    toggleBtn: "text-gray-700 hover:text-indigo-600 transition",
  },

  layout: {
    wrapper: "flex min-h-screen",
    sidebarBase: "fixed top-0 left-0 h-full w-64 p-6 space-y-6 z-40",
    contentWrapper: "flex-1 flex flex-col transition-all duration-300",
    contentShift: "md:ml-64",
    navbar: "h-16 flex items-center justify-between px-6",
    content: "p-6",
    navItem: "px-3 py-2 rounded-lg transition cursor-pointer",
  },

  animation: {
    sidebar: {
      initial: { x: -250 },
      animate: { x: 0 },
      exit: { x: -250 },
      transition: { duration: 0.3 },
    },
    contentFade: {
      initial: { opacity: 0 },
      animate: { opacity: 1 },
      transition: { duration: 0.4 },
    },
  },
};
